blocks.body:
{
    "level": "B1–B2",
    "intro": "W tym temacie dowiesz się <strong>Pytań negatywnych</strong> - pytań w formie przeczącej, które wyrażają zaskoczenie, zaskoczenie lub oczekiwanie określonej odpowiedzi.",
    "rules": [
        {
            "label": "STRUKTURA",
            "color": "emerald",
            "text": "<strong>Forma przecząca</strong> czasownik pomocniczy:",
            "example": "Nie wiesz? Czy ona nie przyjdzie?"
        },
        {
            "label": "ZNACZENIE",
            "color": "blue",
            "text": "<strong>Niespodzianka</strong> czy oczekiwanie:",
            "example": "Nie lubisz kawy? (zaskoczony)"
        },
        {
            "label": "ODPOWIEDŹ",
            "color": "amber",
            "text": "<strong>Tak/Nie</strong> w treści, a nie w formie:",
            "example": "Nie wiesz? - Tak. / Nie, nie."
        }
    ]
}

{
    "title": "1. Czym są pytania przeczące?",
    "intro": "Pytania przeczące to pytania z przeczącą formą czasownika posiłkowego:",
    "items": [
        {
            "label": "Pytanie regularne",
            "title": "Czy wiesz?",
            "subtitle": "Pytanie neutralne"
        },
        {
            "label": "Pytanie przeczące pytanie",
            "title": "Nie wiesz?",
            "subtitle": "Zaskoczenie czy oczekiwanie"
        },
        {
            "label": "Wyróżnienie",
            "title": "Podtekst emocjonalny",
            "subtitle": "Wyraża postawę głośnik"
        }
    ]
}

{
    "title": "2. Pytania przeczące z DO/DOES/DID",
    "sections": [
        {
            "label": "Present Simple",
            "color": "emerald",
            "description": "W czasie Present Simple używamy <strong>nie/nie</strong>:",
            "examples": [
                {
                    "en": "Nie lubisz kawy?",
                    "ua": "Nie lubisz kawy? (niespodzianka)"
                },
                {
                    "en": "Czy ona tu nie pracuje?",
                    "ua": "Czy ona tu nie pracuje? (czekam na „tak”)"
                },
                {
                    "en": "Nie znają odpowiedzi?",
                    "ua": "Nie znają odpowiedzi?"
                },
                {
                    "en": "Czy on nie mówi po angielsku?",
                    "ua": "Czy on nie mówi po angielsku?"
                }
            ]
        },
        {
            "label": "Przeszłość Proste",
            "color": "sky",
            "description": "W czasie Past Simple używamy <strong>nie</strong>:",
            "examples": [
                {
                    "en": "Nie widziałeś filmu?",
                    "ua": "Nie widziałeś filmu?"
                },
                {
                    "en": "Nie zadzwoniła ty?",
                    "ua": "Nie dzwoniła do ciebie?"
                },
                {
                    "en": "Czy nie przyjechali wczoraj? ",
                    "ua": "Czy nie przyszli wczoraj? do/does/did:"
                },
                {
                    "en": "Didn't it rain last night?",
                    "ua": "Хіба вчора ввечері не йшов дощ?"
                }
            ]
        },
        {
            "label": "Структура",
            "color": "purple",
            "description": "Формула заперечного питання з do/does/did:",
            "examples": [
                {
                    "en": "Nie/Nie/Nie zrobił + Podmiot + Czasownik?",
                    "ua": "Forma przecząca + Podmiot + Czasownik?"
                }
            ],
            "note": "📌 Czasownik główny pozostaje w formie podstawowej"
        }
    ]
}

{
    "title": "3. Pytania przeczące z TO BE",
    "sections": [
        {
            "label": "Present Simple — ISN'T/AREN'T",
            "color": "blue",
            "description": "Z <strong>to be</strong> w czasie Present Simple używamy is't/aren't:",
            "examples": [
                {
                    "en": "Czyż nie ona szczęśliwa?",
                    "ua": "Czyż nie jest szczęśliwa? szczęśliwy?"
                },
                {
                    "en": "Nie jesteś gotowy?",
                    "ua": "Nie jesteś gotowy?"
                },
                {
                    "en": "Czy to nie jest drogie?",
                    "ua": "Czy nie jest drogie?"
                },
                {
                    "en": "Czyż nie są na w domu?",
                    "ua": " w domu?"
                }
            ]
        },
        {
            "label": "Past Simple — WASN'T/WEREN'T",
            "color": "amber",
            "description": "W czasie Past Simple używamy was't/weren't:",
            "examples": [
                {
                    "en": "Czy on nie był wczoraj w pracy? zmęczony?",
                    "ua": "Хіба він не був на роботі вчора?"
                },
                {
                    "en": "Weren't you tired?",
                    "ua": "Хіба ти не був втомлений?"
                },
                {
                    "en": "Czy nie było to trudne?",
                    "ua": "Czy nie było to trudne?"
                },
                {
                    "en": "Czy nie byli szczęśliwi?",
                    "ua": "Czy nie byli szczęśliwi?"
                }
            ]
        },
        {
            "label": "Formalne wariant",
            "color": "rose",
            "description": "W języku formalnym możesz użyć pełnej formy:",
            "examples": [
                {
                    "en": "Czy ona nie jest szczęśliwa?",
                    "ua": "Nie jest szczęśliwa? (formalny)"
                },
                {
                    "en": "Nie jesteś gotowy?",
                    "ua": "Nie jesteś gotowy? (formalne)"
                }
            ],
            "note": "📌 Prawda? — potoczne, prawda? - formalne"
        }
    ]
}

{
    "title": "4. Pytania przeczące z czasownikami modalnymi",
    "sections": [
        {
            "label": "NIE MOŻNA / NIE MOGĘ",
            "color": "emerald",
            "description": "Z wyrazem <strong>can/could</strong> używamy nie mogę/nie mogę:",
            "examples": [
                {
                    "en": "Nie umiesz pływać?",
                    "ua": " pływać?"
                },
                {
                    "en": "Nie umiała prowadzić?",
                    "ua": "Nie umiała prowadzić?"
                },
                {
                    "en": "Nie mogli nam pomóc?",
                    "ua": "Nie mogliby nam pomóc?"
                }
            ]
        },
        {
            "label": "NIE / CZY NIE",
            "color": "sky",
            "description": "Z <strong>will/would</strong> używamy will't/wouldn't:",
            "examples": [
                {
                    "en": "Nie przyjdziesz?",
                    "ua": "Nie przyjdziesz?[[[CODX_29]]]Czy ona nie chciałaby to?"
                },
                {
                    "en": "Wouldn't she like it?",
                    "ua": "Czy by jej się to podobało? czy się nie spóźnią?"
                },
                {
                    "en": "Won't they be late?",
                    "ua": "Czy się nie spóźnią?"
                }
            ]
        },
        {
            "label": "NIE POWINNO / NIE MOŻE",
            "color": "purple",
            "description": "Inne modały również mogą mieć formę ujemną:",
            "examples": [
                {
                    "en": "Nie powinniśmy iść?",
                    "ua": "Czy nie powinienem czekać?"
                },
                {
                    "en": "Czy nie powinienem czekać? modalny + podmiot + czasownik",
                    "ua": "Хіба мені не треба чекати?"
                }
            ],
            "note": "📌 Негативна форма модального + підмет + дієслово"
        }
    ]
}

{
    "title": "5. Pytania przeczące z innymi czasami",
    "sections": [
        {
            "label": "Present Perfect",
            "color": "blue",
            "description": "W czasie Present Perfect używamy Have't/hasn't:",
            "examples": [
                {
                    "en": "Nie widziałeś filmu?",
                    "ua": "Nie widziałeś film?"
                },
                {
                    "en": "Czy ona jeszcze nie skończyła? Ving:",
                    "ua": "Хіба вона ще не закінчила?"
                },
                {
                    "en": "Haven't they arrived?",
                    "ua": "Хіба вони не приїхали?"
                }
            ]
        },
        {
            "label": "Present Continuous",
            "color": "amber",
            "description": "У Present Continuous використовуємо isn't/aren't + Ving:",
            "examples": [
                {
                    "en": "Nie pracujesz teraz?",
                    "ua": "Ona nie nadchodzi?"
                },
                {
                    "en": "Czy ona nie nadchodzi?",
                    "ua": "Ona nie nadchodzi? czy oni nie grają?"
                },
                {
                    "en": "Aren't they playing?",
                    "ua": "Хіба вони не граються?"
                }
            ]
        },
        {
            "label": "Past Continuous",
            "color": "rose",
            "description": "W czasie Past Continuous używamy was't/weren't + Ving:",
            "examples": [
                {
                    "en": "Nie spałeś?",
                    "ua": "Nie spałeś? spała?"
                },
                {
                    "en": "Czy ona się nie uczyła?",
                    "ua": "Czy ona się nie uczyła?"
                }
            ],
            "note": "📌Struktura: forma przecząca czasownika posiłkowego + podmiot + część główna"
        }
    ]
}

{
    "title": "6. Znaczenie i zastosowanie pytań negatywnych",
    "sections": [
        {
            "label": "Niespodzianka",
            "color": "emerald",
            "description": "Wyraź <strong>zaskoczenie</strong>, że coś jest nie tak, jak się spodziewano:",
            "examples": [
                {
                    "en": "Nie lubisz pizzy? Każdy lubi pizzę!",
                    "ua": "Nie lubisz pizzy? Każdy lubi pizzę!"
                },
                {
                    "en": "Czy ona nie przyjdzie? Myślałam, że tak.",
                    "ua": "Czy ona nie wychodzi? Myślałem, że przyjdzie."
                }
            ]
        },
        {
            "label": "Czekam na pozytywną odpowiedź",
            "color": "sky",
            "description": "Oczekujemy, że odpowiedź będzie twierdząca:",
            "examples": [
                {
                    "en": "Nie otrzymałeś mojego e-maila?",
                    "ua": "Nie otrzymałeś mojej wiadomości? (czekam na „got”)"
                },
                {
                    "en": "Czy on tu nie pracuje?",
                    "ua": "Czy on tu nie pracuje? (myślę, że to działa)"
                }
            ]
        },
        {
            "label": "Uprzejma prośba lub oferta",
            "color": "purple",
            "description": "Może brzmieć delikatniej i uprzejmie:",
            "examples": [
                {
                    "en": "Nie napijesz się herbaty?",
                    "ua": "Nie napijesz się herbaty? (grzeczne zaproszenie)"
                },
                {
                    "en": "Nie usiądziesz?",
                    "ua": "Nie usiądziesz? (uprzejma prośba)"
                }
            ]
        },
        {
            "label": "Krytyka lub sarkazm",
            "color": "rose",
            "description": "Może brzmieć jak krytyka (w zależności od tonu):",
            "examples": [
                {
                    "en": "Czy nigdy nie słuchasz?",
                    "ua": "Czy w ogóle słuchasz? (krytyka)"
                },
                {
                    "en": "Czyż ci tego nie mówiłem?",
                    "ua": "Czyż ci tego nie mówiłem? (sarkazm)"
                }
            ],
            "note": "⚠️ Intonacja i kontekst są bardzo ważne!"
        }
    ]
}

{
    "title": "7. Jak odpowiadać na pytania negatywne",
    "sections": [
        {
            "label": "Odpowiadaj zgodnie z treścią",
            "color": "emerald",
            "description": "Odpowiadamy <strong>Tak/Nie zgodnie z treścią</strong>, a nie według formy pytania:",
            "examples": [
                {
                    "en": "P: Nie lubisz kawy? — O: Tak, mam. (Kocham)",
                    "ua": "Pytanie jest przeczące, ale odpowiedź jest pozytywna"
                },
                {
                    "en": "P: Nie lubisz kawy? — O: Nie, nie mam. (nie podoba mi się)",
                    "ua": "Zarówno pytanie, jak i odpowiedź są negatywne"
                }
            ]
        },
        {
            "label": "Uważaj na zamieszanie",
            "color": "amber",
            "description": "W niektórych językach logika jest inna, więc bądź ostrożny:",
            "examples": [
                {
                    "en": "Nie wiesz? - Tak, wiem. (Angielski)",
                    "ua": "Nie wiesz? — Tak, wiem."
                },
                {
                    "en": "Nie wiesz? - Nie, nie wiem. (Angielski)",
                    "ua": "Nie wiesz? — Nie, nie wiem."
                }
            ]
        },
        {
            "label": "Pełna odpowiedź jest lepsza",
            "color": "sky",
            "description": "Dla jasności lepiej jest podać pełną odpowiedź:",
            "examples": [
                {
                    "en": "P: Czy ona nie przyjdzie? — A: Nie, ona nie przyjdzie.",
                    "ua": "Jasna odpowiedź pozwoli uniknąć nieporozumień"
                },
                {
                    "en": "P: Nie podoba Ci się to? Odpowiedź: Tak, bardzo mi się to podoba. Porównanie pytań normalnych i przeczących",
                    "ua": "Повна відповідь зрозуміліша"
                }
            ],
            "note": "📌 Yes = згоден з позитивом, No = згоден з негативом"
        }
    ]
}

{
    "title": "8. Порівняння звичайних та заперечних питань",
    "intro": "Różnice między pytaniami normalnymi i przeczącymi:",
    "rows": [
        {
            "en": "Pytanie pozytywne",
            "ua": "Normalne pytanie",
            "note": "Czy lubisz kawę? — pytanie neutralne"
        },
        {
            "en": "Pytanie negatywne",
            "ua": "Pytanie negatywne",
            "note": "Nie lubisz kawy? odpowiedzi będące zaskoczeniem lub oczekiwaniem"
        },
        {
            "en": "Emotion",
            "ua": "Емоція",
            "note": "Заперечне питання має емоційний підтекст"
        },
        {
            "en": "Expectation",
            "ua": "Очікування",
            "note": "Заперечне питання часто очікує певної відповіді"
        },
        {
            "en": "Odpowiedź",
            "ua": "Odpowiedz",
            "note": "Tak/Nie na podstawie treści, a nie formy pytania"
        }
    ],
    "warning": "📌 Pytania negatywne wyrażają <strong>nastawienie mówiącego</strong>, a nie tylko pytają o fakt"
}

{
    "title": "9. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Pomieszanie z odpowiedzią (odpowiedź zgodnie z formą, a nie treścią).",
            "wrong": "❌ P: Nie podoba Ci się? Odpowiedź: Tak, nie. (źle)",
            "right": " ✅ <span class="font-mono">P: Nie podoba Ci się to? O: Nie, nie mam. / Tak, wiem. 3"
        },
        {
            "label": "Помилка 2",
            "color": "amber",
            "title": "Неправильний порядок слів (формальний варіант).",
            "wrong": "❌ You don't like coffee?",
            "right": "✅ <span class="font-mono">Don't you like coffee?</span>"
        },
        {
            "label": "Помилка 3",
            "color": "sky",
            "title": "Niepoprawna forma czasownika głównego.",
            "wrong": "❌ Czy jej się to nie podoba?",
            "right": "​​​​​​​​ podtekst."
        },
        {
            "label": "Помилка 4",
            "color": "purple",
            "title": "Використання заперечного питання без емоційного підтексту.",
            "wrong": "❌ Nie masz długopisu? (jeśli pytasz neutralnie)",
            "right": " ✅ <span class="font-mono">Czy masz długopis? (neutralny)</span>"
        }
    ]
}

{
    "title": "11. Ćwicz",
    "select_title": "Ćwiczenie 1. Wybierz właściwą formę",
    "select_intro": "Wybierz prawidłowe pytanie przeczące.",
    "selects": [
        {
            "label": "a) Nie lubisz kawy? / b) Nie lubisz kawy? / c) Nie lubisz kawy?",
            "prompt": "Która forma jest poprawna?"
        },
        {
            "label": "a) Ona nie jest szczęśliwa? / b) Czy nie jest szczęśliwa? / c) Czy ona nie jest szczęśliwa?",
            "prompt": "Jaka jest forma potoczna?"
        },
        {
            "label": "a) Nie umiesz pływać? / b) Nie umiesz pływać? / c) Nie umiesz pływać?",
            "prompt": "Jaka forma jest poprawna?"
        }
    ],
    "options": [
        "a",
        "b",
        "c[[CODX_SEG_19]]]Ćwiczenie 2. Utwórz pytanie przeczące negatywny."
    ],
    "input_title": "Вправа 2. Створи заперечне питання",
    "input_intro": "Перетвори звичайне питання на заперечне.",
    "inputs": [
        {
            "before": "Czy wiesz? → ",
            "after": ""
        },
        {
            "before": "Czy ona nadchodzi? → ",
            "after": ""
        },
        {
            "before": "Czy mogą pomóc? → ",
            "after": ""
        },
        {
            "before": "Widziałeś to? → ",
            "after": ""
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd w pytaniu przeczącym.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "Nie lubisz kawy?",
            "example_target": "Nie lubisz kawy?"
        },
        {
            "original": "1. Czy jej się to nie podoba?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "2. Nie umiesz pływać?",
            "placeholder": "Napraw błąd"
        },
        {
            "original": "3. Nie wiesz?",
            "placeholder": "Popraw błąd"
        }
    ]
}

{
    "title": "Inne tematy z sekcji Rodzaje zdań pytających",
    "items": [
        {
            "label": "Tak/Nie Pytania — Pytania ogólne",
            "current": false
        },
        {
            "label": "Wh-Pytania — Pytania specjalne",
            "current": false
        },
        {
            "label": "Alternatywa Pytania — pytania alternatywne",
            "current": false
        },
        {
            "label": "Tagi pytań — pytania przekrojowe",
            "current": false
        },
        {
            "label": "Pytania negatywne — pytania przeczące (bieżące)",
            "current": true
        }
    ]
}
